1030	 * CLUSTER_REDIR_DOWN_UNBOUND if the request addresses a slot which is
1031	 * not bound to any node. In this case the cluster global state should be
1032	 * already "down" but it is fragile to rely on the update of the global state,
1033	 * so we also handle it here.
1034	 *
1035	 * CLUSTER_REDIR_DOWN_STATE and CLUSTER_REDIR_DOWN_RO_STATE if the cluster is
1036	 * down but the user attempts to execute a command that addresses one or more keys. */
1037	clusterNode *getNodeByQuery(client *c, int *error_code) {
1038	    clusterNode *myself = getMyClusterNode();
1039	    clusterNode *n = NULL;
1040	    robj *firstkey = NULL;
1041	    int multiple_keys = 0;
1042	    multiState *ms, _ms;
1043	    multiCmd mc;
1044	    int i, migrating_slot = 0, importing_slot = 0, missing_keys = 0, existing_keys = 0;
1045	
1046	    /* Slot must be calculated in advance, or cross-slot or no keys detected. */
1047	    serverAssert(c->slot >= 0 || c->read_flags & (READ_FLAGS_NO_KEYS | READ_FLAGS_CROSSSLOT));
1048	
1049	    /* Allow any key to be set if a module disabled cluster redirections. */
1050	    if (server.cluster_module_flags & CLUSTER_MODULE_FLAG_NO_REDIRECTION) return myself;
1051	
1052	    /* Set error code optimistically for the base case. */
1053	    if (error_code) *error_code = CLUSTER_REDIR_NONE;
1054	
1055	    /* Modules can turn off Cluster redirection: this is useful
1056	     * when writing a module that implements a completely different
1057	     * distributed system. */
1058	
1059	    /* Determine transaction slot and return early on cross-slot. */
1060	    if (c->cmd->proc == execCommand && c->flag.multi) {
1061	        int slot = -1;
1062	        for (i = 0; i < c->mstate->count; i++) {
1063	            if (slot == -1) {
1064	                slot = c->mstate->commands[i].slot;
1065	            } else if (c->mstate->commands[i].slot != -1 && c->mstate->commands[i].slot != slot) {
1066	                if (error_code) *error_code = CLUSTER_REDIR_CROSS_SLOT;
1067	                return NULL;
1068	            }
1069	        }
1070	        /* EXEC will execute all queued commands in the transaction, so we
1071	         * overwrite the EXEC commands's slot with the transaction's slot. */
1072	        c->slot = slot;
1073	    } else if (c->read_flags & READ_FLAGS_CROSSSLOT) {
1074	        if (error_code) *error_code = CLUSTER_REDIR_CROSS_SLOT;
1075	        return NULL;
1076	    }
1077	
1078	    /* No key at all in command? then we can serve the request
1079	     * without redirections or errors in all the cases. */
1080	    if (c->slot == -1) return myself;
1081	
1082	    n = getNodeBySlot(c->slot);
1083	
1084	    /* If a slot is not served, we are in "cluster down" state.
1085	     * This check is done early to preserve historical behavior. */
1086	    if (n == NULL) {
1087	        if (error_code) *error_code = CLUSTER_REDIR_DOWN_UNBOUND;
1088	        return NULL;
1089	    }
1090	
1091	    /* If we are migrating or importing this slot, we need to check
1092	     * if we have all the keys in the request (the only way we
1093	     * can safely serve the request, otherwise we return a TRYAGAIN
1094	     * error). To do so we set the importing/migrating state and
1095	     * increment a counter for every missing key. */
1096	    if (clusterNodeIsPrimary(myself) || c->flag.readonly) {
1097	        if (n == clusterNodeGetPrimary(myself) && getMigratingSlotDest(c->slot) != NULL) {
1098	            migrating_slot = 1;
1099	        } else if (getImportingSlotSource(c->slot) != NULL) {
1100	            importing_slot = 1;
1101	        }
1102	    }
1103	
1104	    uint64_t cmd_flags = getCommandFlags(c);
1105	
1106	    /* Only valid for sharded pubsub as regular pubsub can operate on any node and bypasses this layer. */
1107	    int pubsubshard_included =
1108	        (cmd_flags & CMD_PUBSUB) || (c->cmd->proc == execCommand && (c->mstate->cmd_flags & CMD_PUBSUB));
1109	
1110	    /* If we're importing or migrating the slot, we need to do some more checks:
1111	     *
1112	     *   1. Go over all the keys to count existing keys and missing keys that we
1113	     *      need for TRYAGAIN and ASK redirects.
1114	     *   2. Check for some commands that are forbiddedn during slot migration.
1115	     *
1116	     * Skip this if we're not importing or migrating this slot. */
1117	    if (!migrating_slot && !importing_slot) goto after_checking_each_key;
1118	
1119	    /* We handle all the cases as if they were EXEC commands, so we have
1120	     * a common code path for everything */
1121	    if (c->cmd->proc == execCommand) {
1122	        /* If CLIENT_MULTI flag is not set EXEC is just going to return an
1123	         * error. */
1124	        if (!c->flag.multi) return myself;
1125	        ms = c->mstate;
1126	    } else {
