1128	         * structure if the client is not in MULTI/EXEC state, this way
1129	         * we have a single codepath below. */
1130	        ms = &_ms;
1131	        _ms.commands = &mc;
1132	        _ms.count = 1;
1133	        mc.argv = c->argv;
1134	        mc.argc = c->argc;
1135	        mc.cmd = c->cmd;
1136	    }
1137	
1138	    serverDb *origDb = c->db;
1139	    serverDb *currentDb = origDb;
1140	
1141	    /* Check for multiple keys, existing keys, missing keys. */
1142	    for (i = 0; i < ms->count; i++) {
1143	        struct serverCommand *mcmd;
1144	        robj **margv;
1145	        int margc, numkeys, j;
1146	        keyReference *keyindex;
1147	
1148	        mcmd = ms->commands[i].cmd;
1149	        margc = ms->commands[i].argc;
1150	        margv = ms->commands[i].argv;
1151	
1152	        getKeysResult result;
1153	        initGetKeysResult(&result);
1154	        numkeys = getKeysFromCommand(mcmd, margv, margc, &result);
1155	        keyindex = result.keys;
1156	
1157	        if (mcmd->proc == selectCommand) {
1158	            /* Failed SELECT is ignored since it doesn't modify the database. */
1159	            long long id;
1160	            if (getLongLongFromObject(margv[1], &id) == C_OK && selectDb(c, id) == C_OK) {
1161	                currentDb = c->db;
1162	                selectDb(c, origDb->id);
1163	            }
1164	        }
1165	
1166	        for (j = 0; j < numkeys; j++) {
1167	            robj *thiskey = margv[keyindex[j].pos];
1168	
1169	            if (firstkey == NULL) {
1170	                /* This is the first key we see. */
1171	                firstkey = thiskey;
1172	            } else {
