1174	                 * the same key/channel as the first we saw. */
1175	                if (importing_slot && !multiple_keys && !equalStringObjects(firstkey, thiskey)) {
1176	                    /* Flag this request as one with multiple different
1177	                     * keys/channels when the slot is in importing state. */
1178	                    multiple_keys = 1;
1179	                }
1180	            }
1181	
1182	            /* Block MOVE command as the destination key is not expected to exist, and we don't know if it was migrated */
1183	            if (mcmd->proc == moveCommand) {
1184	                if (error_code) *error_code = CLUSTER_REDIR_UNSTABLE;
1185	                getKeysFreeResult(&result);
1186	                return NULL;
1187	            }
1188	
1189	            /* Block the COPY command if it's cross-DB to keep the code simple.
1190	             * Allowing cross-DB COPY is possible, but it would require looking up the second key in the target DB.
1191	             * The command should only be allowed if the key exists. We may revisit this decision in the future. */
1192	            if (mcmd->proc == copyCommand &&
1193	                margc >= 4 && !strcasecmp(margv[3]->ptr, "db")) {
1194	                long long value;
1195	                if (getLongLongFromObject(margv[4], &value) != C_OK || value != currentDb->id) {
1196	                    if (error_code) *error_code = CLUSTER_REDIR_UNSTABLE;
1197	                    getKeysFreeResult(&result);
1198	                    return NULL;
1199	                }
1200	            }
1201	
1202	            /* Migrating / Importing slot? During exec we count keys we don't have.
1203	             * If it is pubsubshard command, it isn't required to check
1204	             * the channel being present or not in the node during the
1205	             * slot migration, the channel will be served from the source
1206	             * node until the migration completes with CLUSTER SETSLOT <slot>
1207	             * NODE <node-id>. */
1208	            int flags = LOOKUP_NOTOUCH | LOOKUP_NOSTATS | LOOKUP_NONOTIFY | LOOKUP_NOEXPIRE;
1209	            if (!pubsubshard_included &&
1210	                (!c->flag.multi || (c->flag.multi && c->cmd->proc == execCommand))) {
1211	                /* Multi/Exec validation happens on exec */
1212	                if (lookupKeyReadWithFlags(currentDb, thiskey, flags) == NULL)
1213	                    missing_keys++;
1214	                else
1215	                    existing_keys++;
1216	            }
1217	        }
1218	        getKeysFreeResult(&result);
1219	    }
1220	
1221	after_checking_each_key:
