int clusterMoveNodeSlots(clusterNode *from_node, clusterNode *to_node) {
    int processed = 0;
    for (int j = 0; j < CLUSTER_SLOTS; j++) {
        if (clusterNodeCoversSlot(from_node, j)) {
            clusterDelSlot(j);
            clusterAddSlot(to_node, j);
            processed++;
        }

        /* If an ongoing slot migration references the old primary, update it
         * to the newly promoted primary as part of the same failover handling.
         * Otherwise nodes that learn about the old primary's demotion before
         * learning about the new primary's slot bitmap can keep stale open-slot
         * endpoints until another gossip update happens. */
        if (server.cluster->migrating_slots_to[j] == from_node) {
            server.cluster->migrating_slots_to[j] = to_node;
        }
        if (server.cluster->importing_slots_from[j] == from_node) {
            server.cluster->importing_slots_from[j] = to_node;
        }
    }
    return processed;
}

